rule.example:
import java.util.regex.Pattern

class Bad {
    fun isValid(input: String): Boolean {
        val p = Pattern.compile("[A-Z][a-z]+") // violation: compiled every call
        return p.matcher(input).matches()
    }
}

class Good {
    companion object {
        private val WORD_PATTERN = Pattern.compile("[A-Z][a-z]+") // ok: compiled once
    }

    fun isValid(input: String): Boolean = WORD_PATTERN.matcher(input).matches()
}
